#include <stdio.h>
#include <stdlib.h>

typedef struct Node {int key; int cnt; struct Node *next;} Node;

#define MOD 1000003
Node *table[MOD];
unsigned int hash_int(int x){return ((unsigned)x * 2654435761u) % MOD;}
Node* find(int x){unsigned int h=hash_int(x); for(Node* p=table[h];p;p=p->next) if(p->key==x) return p; return NULL;}
void inc(int x){Node* p=find(x); if(p){p->cnt++; return;} unsigned int h=hash_int(x); Node* n= (Node*)malloc(sizeof(Node)); n->key=x; n->cnt=1; n->next=table[h]; table[h]=n;}
void clear(){for(int i=0;i<MOD;i++){Node* p=table[i]; while(p){Node* q=p; p=p->next; free(q);} table[i]=NULL;}}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        clear();
        int maxFreq=0;
        for(int i=0;i<N;i++){
            int a; scanf("%d", &a);
            inc(a);
        }
        for(int i=0;i<MOD;i++){
            for(Node* p=table[i]; p; p=p->next){
                if(p->cnt>maxFreq) maxFreq=p->cnt;
            }
        }
        if(maxFreq==N) printf("0\n");
        else if(maxFreq==1) printf("-1\n");
        else printf("%d\n", N - maxFreq + 1);
    }
    return 0;
}

