#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        freq = {}
        max_freq = 0
        for _ in range(N):
            a = int(next(it))
            cnt = freq.get(a, 0) + 1
            freq[a] = cnt
            if cnt > max_freq:
                max_freq = cnt
        if max_freq == N:
            out.append('0')
        elif max_freq == 1:
            out.append('-1')
        else:
            out.append(str(N - max_freq + 1))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

